class Solution {
public:
    vector<int> beautifulIndices(string s, string a, string b, int k) {
        vector<int> aIndices, bIndices, result;
        for (int i = 0; i <= s.size() - a.size(); ++i) {
            if (s.substr(i, a.size()) == a) aIndices.push_back(i);
        }
        for (int i = 0; i <= s.size() - b.size(); ++i) {
            if (s.substr(i, b.size()) == b) bIndices.push_back(i);
        }
        int bIndex = 0;
        for (int aIndex : aIndices) {
            while (bIndex < bIndices.size() && abs(aIndex - bIndices[bIndex]) > k) ++bIndex;
            if (bIndex < bIndices.size() && abs(aIndex - bIndices[bIndex]) <= k) result.push_back(aIndex);
        }
        return result;
    }
};
